<template>
    <div class="post-detail" v-if="post">
      <div class="post-container">
        <h1>{{ post.title }}</h1>
        <div class="post-meta">
          <span class="date">{{ post.date }}</span>
        </div>
        <div class="post-content markdown-body" v-html="renderedContent"></div>
      </div>
    </div>
  </template>
  
  <script>
  import { computed } from 'vue'
  import { useRoute } from 'vue-router'
  import { useStore } from 'vuex'
  import { marked } from 'marked'
  import katex from 'katex'
  import 'katex/dist/katex.min.css'
  import hljs from 'highlight.js'
  import 'highlight.js/styles/github-dark.css'
  
  export default {
    name: 'PostDetailPage',
    setup() {
      const route = useRoute()
      const store = useStore()
      
      marked.setOptions({
        highlight: function(code, lang) {
          if (lang && hljs.getLanguage(lang)) {
            try {
              return hljs.highlight(code, { language: lang }).value
            } catch (error) {
              console.warn('Failed to highlight code block:', error)
              return code // 返回原始代码作为后备
            }
          }
          return hljs.highlightAuto(code).value
        },
        breaks: true,
        langPrefix: 'hljs language-'
      })
  
      const renderer = new marked.Renderer()
      const originalCodeRenderer = renderer.code.bind(renderer)
      renderer.code = (code, language) => {
        if (language === 'math') {
          try {
            return katex.renderToString(code, { displayMode: true })
          } catch (err) {
            return `<pre>${err}</pre>`
          }
        }
        const highlightedCode = originalCodeRenderer(code, language)
        return `<div class="code-block-wrapper">${highlightedCode}</div>`
      }
      
      marked.use({ renderer })
  
      const post = computed(() => 
        store.state.posts.find(p => p.id === parseInt(route.params.id))
      )
      
      const renderedContent = computed(() => {
        if (!post.value) return ''
        return marked(post.value.content)
      })
      
      return {
        post,
        renderedContent
      }
    }
  }
  </script>
  
  <style>
  /* 样式部分保持不变 */

  .post-container {
    max-width: 800px;
    margin: 0 auto;
    background-color: #d5f0f0;
    padding: 2rem;
    border-radius: 8px;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.1);
    border:0.5px solid black;
  }
  
  .post-content {
    line-height: 1.8;
    color: #2c3e50;
    font-size: 1.1rem;
  }
  
  .post-content h1,
  .post-content h2,
  .post-content h3,
  .post-content h4 {
    margin-top: 2rem;
    margin-bottom: 1rem;
    font-weight: 600;
  }
  
  .code-block-wrapper {
    margin: 1.5rem 0;
    border-radius: 8px;
    overflow: hidden;
  }
  
  .code-block-wrapper pre {
    margin: 0 !important;
    padding: 1rem;
    background-color: #95d7d1 !important;
    border-radius: 8px;
    overflow-x: auto;
  }
  
  .code-block-wrapper code {
    font-family: 'Fira Code', Consolas, Monaco, 'Andale Mono', monospace;
    font-size: 0.9rem;
    line-height: 1.5;
  }
  
  .post-content p code,
  .post-content li code {
    background-color: #f1f1f1;
    color: #e83e8c;
    padding: 0.2rem 0.4rem;
    border-radius: 4px;
    font-size: 0.9em;
    font-family: Consolas, Monaco, 'Andale Mono', monospace;
  }
  
  .post-content blockquote {
    border-left: 4px solid #42b883;
    margin: 1.5rem 0;
    padding: 0.5rem 0 0.5rem 1rem;
    background-color: #f8f8f8;
    color: #666;
  }
  
  .post-content ul,
  .post-content ol {
    padding-left: 1.5rem;
    margin: 1rem 0;
  }
  
  .post-content a {
    color: #42b883;
    text-decoration: none;
    border-bottom: 1px solid #42b883;
  }
  
  .post-content a:hover {
    color: #3aa876;
    border-bottom-color: #3aa876;
  }
  
  .post-content table {
    width: 100%;
    border-collapse: collapse;
    margin: 1rem 0;
  }
  
  .post-content th,
  .post-content td {
    border: 1px solid #ddd;
    padding: 0.75rem;
    text-align: left;
  }
  
  .post-content th {
    background-color: #f5f5f5;
  }
  </style>